import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "src/utils/Common";
import { getAllTeamList, handleDeleteTeamMember } from "src/components/services/TeamDetails";
import { CButton } from "@coreui/react";
import DataTable from "react-data-table-component";
import { customStyles } from "../../utils/tableCustomStyles";
import { tableTeamConstant } from "./tableTeamConstant";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const teamList = () => {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchTeamList();
        window.addEventListener('error', e => {
            if (e.message === 'ResizeObserver loop limit exceeded' || e.message === 'Script error.') {
                const resizeObserverErrDiv = document.getElementById(
                    'webpack-dev-server-client-overlay-div'
                )
                const resizeObserverErr = document.getElementById(
                    'webpack-dev-server-client-overlay'
                )
                if (resizeObserverErr) {
                    resizeObserverErr.setAttribute('style', 'display: none');
                }
                if (resizeObserverErrDiv) {
                    resizeObserverErrDiv.setAttribute('style', 'display: none');
                }
            }
        })
    }, []);

    const handleDelete = async (id) => {
        const response = await handleDeleteTeamMember(id);
        if (response?.code === 200) {
            fetchTeamList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const fetchTeamList = async () => {
        const response = await getAllTeamList();
        let data = [];
        if (response?.code === 200) {
            response?.results && response?.results.map((item) => {
                data.push({ name: item?.name, position: item?.position, quote: item?.quote, imageUrl: item?.imageUrl, id: item?._id, "status": item?.status, createTime: epochTogmt(item?.createTime) });
            });
        }
        setRowData(data);
    };

    return (<div className='row'>
        <div className="col2Large">
            <DataTable
                title="Team"
                columns={tableTeamConstant(fetchTeamList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                //actions={this.actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
        {authService.getPermission("TEAM_CREATE") &&  <div className='col-sm-12'>
            <Link to={"/team/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Team"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default teamList;
